"use server";

import { prisma } from "@/lib/prisma";
import type { Game, DailyGame } from "@/lib/gameTypes";

function toPuzzleKeyUTC(d: Date) {
  return d.toISOString().slice(0, 10);
}

function dayIndexUTC(d: Date) {
  const year = d.getUTCFullYear();
  const start = Date.UTC(year, 0, 1);
  const today = Date.UTC(year, d.getUTCMonth(), d.getUTCDate());
  return Math.floor((today - start) / (24 * 60 * 60 * 1000));
}

export async function getDailyGame(_date = new Date()): Promise<DailyGame> {
  throw new Error("请使用异步版本 getDailyGameFromDb。");
}

export async function getDailyGameFromDb(date = new Date()): Promise<DailyGame> {
  const all = await prisma.game.findMany({
    include: {
      images: {
        orderBy: { order: "asc" },
      },
    },
    orderBy: { createdAt: "asc" },
  });

  if (!all.length) {
    throw new Error("数据库中还没有 Game 记录，请先用 Prisma Studio 添加。");
  }

  const idx = dayIndexUTC(date) % all.length;
  const g = all[idx]!;

  let acceptable: string[] = [];
  try {
    acceptable = JSON.parse(g.acceptableAnswers || "[]") ?? [];
  } catch {
    acceptable = [];
  }

  return {
    id: g.id,
    slug: g.slug,
    title: g.title,
    acceptableAnswers: acceptable,
    images: g.images
      .sort((a: { order: number }, b: { order: number }) => a.order - b.order)
      .map((img: { url: string }) => img.url),
    puzzleKey: toPuzzleKeyUTC(date),
    maxGuesses: 6,
  };
}

export async function getGameById(id: string): Promise<Game | undefined> {
  const g = await prisma.game.findUnique({
    where: { id },
    include: { images: { orderBy: { order: "asc" } } },
  });
  if (!g) return undefined;

  let acceptable: string[] = [];
  try {
    acceptable = JSON.parse(g.acceptableAnswers || "[]") ?? [];
  } catch {
    acceptable = [];
  }

  return {
    id: g.id,
    slug: g.slug,
    title: g.title,
    acceptableAnswers: acceptable,
    images: g.images
      .sort((a: { order: number }, b: { order: number }) => a.order - b.order)
      .map((img: { url: string }) => img.url),
  };
}

